    if (atLeastWarningLevel(logRecord)) {
      builder.append(logRecord.getLevel().getName())
              .append(": ");
    }
    builder.append(logRecord.getMessage());
    if (thrown != null) {
      builder.append(" [")
              .append(thrown.getMessage())
